--=============================================--
-- MW compatibility check (part I)
--=============================================--
/* More Wonders */
INSERT INTO BuildingClasses (Type)
SELECT		'BUILDINGCLASS_DUMMY_PO_MW'
WHERE EXISTS (SELECT * FROM UnitPromotions WHERE Type='PROMOTION_MARAE');
