	------------------------------
	-- Promotion Help
	------------------------------
	-- World Wonders
	UPDATE Language_en_US SET Text = '+10%[ICON_RANGE_STRENGTH]RCS.' WHERE Tag = 'TXT_KEY_PROMOTION_MARAE_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = 'Unit gains [ICON_CULTURE] [COLOR:255:230:85:255]on Kill[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_ARAHURAHU_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = '+10%[ICON_STRENGTH]CS.' WHERE Tag = 'TXT_KEY_PROMOTION_DAMASCUS_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = '+20% [ICON_WORKER] Work Rate. Unit [COLOR:255:230:85:255]can Enter (cannot Dig on) Enemy Territory without Open Borders Agreement[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_HIDDEN_ARTIFACTS_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = '+1[ICON_ARROW_RIGHT]Movement Point. +10 HP Heal [COLOR:255:230:85:255]on Heal inside Friendly Territory[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_PANAMA_CANAL_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = 'Unit [COLOR:255:230:85:255]can Enter Mountain[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_DARJEELING_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = '+30%[ICON_RANGE_STRENGTH]RCS if unit [COLOR:255:230:85:255]has 20% of its maximum HP or less[ENDCOLOR] [COLOR_GREY](inactive)[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_SANBO_AIR_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = '+30%[ICON_RANGE_STRENGTH]RCS if unit [COLOR:255:230:85:255]has 20% of its maximum HP or less[ENDCOLOR] [COLOR_POSITIVE_TEXT](active)[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_SANBO_AIR_EFFECT_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = 'Unit deals Damage [COLOR:255:230:85:255]to attackng Air Unit[ENDCOLOR] (not available on Submarines). Requires [ICON_RESEARCH][COLOR_RESEARCH_STORED]Flight[ENDCOLOR]. +10%[ICON_STRENGTH]CS/[ICON_RANGE_STRENGTH]RCS if unit [COLOR:255:230:85:255]is adjacent to another Friendly Unit[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_SANBO_SEA_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = 'Bonus[ICON_MOVES]Movement Point [COLOR:255:230:85:255]after crossing Rivers[ENDCOLOR]. +10%[ICON_STRENGTH]CS/[ICON_RANGE_STRENGTH]RCS [COLOR:255:230:85:255]in Rough Terrain[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_SANBO_LAND_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = '+2 [ICON_SWAP] Range.' WHERE Tag = 'TXT_KEY_PROMOTION_WHITE_SANDS_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = 'Double [ICON_MOVES]Movement [COLOR:255:230:85:255]on Tundra and Snow[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_SIBERIAN_RAILWAY_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
	UPDATE Language_en_US SET Text = '+5%[ICON_RANGE_STRENGTH]Offensive RCS. +2 [ICON_SWAP] Range.' WHERE Tag = 'TXT_KEY_PROMOTION_THULE_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');
