	-- Buildings
	UPDATE Language_en_US SET Text = '+50%[ICON_STRENGTH]Offensive CS/[ICON_RANGE_STRENGTH]Offensive RCS [COLOR:255:230:85:255]vs Wounded Units[ENDCOLOR].' WHERE Tag = 'TXT_KEY_PROMOTION_FLETCHER_HELP' AND EXISTS (SELECT * FROM BuildingClasses WHERE Type='BUILDINGCLASS_DUMMY_PO_MW');

